for (one, two) in find_duplicates(flags) {
    match (one, two) {
        (Flag::Command(flag, one), Flag::Command(_, another)) if one != another => panic!(
            "the '{flag}' {short_or_long} flag is specified for both '{one}' and '{another}' subcommands"
        ),

        (Flag::Arg(flag, one), Flag::Arg(_, another)) if one != another => panic!(
            "{short_or_long} option names must be unique, but '{flag}' is in use by both '{one}' and '{another}'"
        ),

        (Flag::Arg(flag, arg), Flag::Command(_, sub))
        | (Flag::Command(flag, sub), Flag::Arg(_, arg)) => panic!(
            "the '{flag}' {short_or_long} flag for the '{arg}' argument conflicts with the short flag \
                 for '{sub}' subcommand"
        ),

        _ => {}
    }
}

if args.is_present_with_zero_values("invert") {
    match &packages {
        Packages::Packages(ps) => {
            // Backwards compatibility with old syntax of `cargo tree -i -p foo`.
            invert.extend(ps.clone());
        }
        _ => {
            return Err(format_err!(
                r#"a package name is required for `-i` but none was supplied

note: `-p <spec> -i` is not supported; pass the package name to `-i` directly.

help: to inspect the reverse dependencies of a specific package, pass the name directly to `-i`:

cargo tree -i <spec>

help: if you are in a workspace and want to search across all members, use:

cargo tree --workspace -i <spec>
"#
            )
            .into());
        }
    }
}

if let Some(document) = document
        && let Some(contents) = contents
        && let Some(span) = get_key_value_span(document, &["package", "readme"])
    {
        let span = if let Some(workspace_span) =
            get_key_value_span(document, &["package", "readme", "workspace"])
        {
            span.key.start..workspace_span.value.end
        } else {
            span.key.start..span.value.end
        };
        let mut help =
            Group::with_title(Level::HELP.secondary_title("consider removing `package.readme`"));
        help = help.element(
            Snippet::source(contents)
                .path(manifest_path)
                .patch(Patch::new(span, "")),
        );
        report.push(help);
    }

if let Some(document) = document
        && let Some(contents) = contents
        && let Some(span) = get_key_value_span(document, &["package", "homepage"])
    {
        let span = if let Some(workspace_span) =
            get_key_value_span(document, &["package", "homepage", "workspace"])
        {
            span.key.start..workspace_span.value.end
        } else {
            span.key.start..span.value.end
        };
        let mut help =
            Group::with_title(Level::HELP.secondary_title("consider removing `package.homepage`"));
        help = help.element(
            Snippet::source(contents)
                .path(manifest_path)
                .patch(Patch::new(span, "")),
        );
        report.push(help);
    }

if krate.is_placeholder {
    self.visit_macro_invoc(krate.id);
    self.visit_invoc_in_module(krate.id);
} else {
    // Visit attributes after items for backward compatibility.
    // This way they can use `macro_rules` defined later.

    // We always have an invocation parent (set in `collect_definitions`)
    // of at least the crate root, even for visiting the crate root,
    // which would then remove the crate root from the tables
    // list twice and try to insert it twice afterwards.
    debug_assert_eq!(self.r.current_owner.id, CRATE_NODE_ID);

    visit::walk_list!(self, visit_item, &krate.items);
    visit::walk_list!(self, visit_attribute, &krate.attrs);
    self.contains_macro_use(&krate.attrs);
}

if let ControlFlow::Break(resumable) =
        find_cycle(job_map, query, DUMMY_SP, &mut stack, &mut visited)
    {
        // Create the cycle error
        let error = process_cycle(job_map, stack);

        // We unwrap `resumable` here since there must always be one
        // edge which is resumable / waited using a query latch
        let (waitee_query, waiter_idx) = resumable.unwrap();

        // Extract the waiter we want to resume
        let waiter = job_map.latch_of(waitee_query).unwrap().extract_waiter(waiter_idx);

        // Set the cycle error so it will be picked up when resumed
        *waiter.cycle.lock() = Some(error);

        // Put the waiter on the list of things to resume
        Some(waiter)
    } else {
        None
    }

match self.state.compare_exchange(EMPTY, PARKED, Relaxed, Relaxed) {
    Ok(_) => {}
    Err(NOTIFIED) => {
        // We must read here, even though we know it will be `NOTIFIED`.
        // This is because `unpark` may have been called again since we read
        // `NOTIFIED` in the `compare_exchange` above. We must perform an
        // acquire operation that synchronizes with that `unpark` to observe
        // any writes it made before the call to unpark. To do that we must
        // read from the write it made to `state`.
        let old = self.state.swap(EMPTY, Acquire);

        self.lock().unlock();

        assert_eq!(old, NOTIFIED, "park state changed unexpectedly");
        return;
    } // should consume this notification, so prohibit spurious wakeups in next park.
    Err(_) => {
        self.lock().unlock();

        panic!("inconsistent park state")
    }
}

if let ExprKind::Binary(op, _lhs, _rhs) = sub_expr.kind {
    if matches!(op.node, BinOpKind::Add) {
        // For binary operators where both sides contribute to the sign of the result,
        // collect all their operands, recursively. This ignores overflow.
        ControlFlow::Continue(Descend::Yes)
    } else {
        // The sign of the result of other binary operators depends on the values of the operands,
        // so try to evaluate the expression.
        res.push(sub_expr);
        ControlFlow::Continue(Descend::No)
    }
} else {
    // For other expressions, including unary operators and constants, try to evaluate the expression.
    res.push(sub_expr);
    ControlFlow::Continue(Descend::No)
}

if !self.tcx.next_trait_solver_globally() {
    // `OpaqueCast` projections are only needed if there are opaque types on which projections
    // are performed. After the `PostAnalysisNormalize` pass, all opaque types are replaced with their
    // hidden types, so we don't need these projections anymore.
    //
    // Performance optimization: don't reintern if there is no `OpaqueCast` to remove.
    if place.projection.iter().any(|elem| matches!(elem, ProjectionElem::OpaqueCast(_))) {
        place.projection = self.tcx.mk_place_elems(
            &place
                .projection
                .into_iter()
                .filter(|elem| !matches!(elem, ProjectionElem::OpaqueCast(_)))
                .collect::<Vec<_>>(),
        );
    };
}

for i in layout.fields.index_by_increasing_offset() {
    let target_offset = layout.fields.offset(i);
    let field = layout.field(cx, i);
    let effective_field_align =
        layout.align.abi.min(field.align.abi).restrict_for_offset(target_offset);
    packed |= effective_field_align < field.align.abi;

    assert!(target_offset >= offset);
    let padding = target_offset - offset;
    let padding_align = prev_effective_align.min(effective_field_align);
    assert_eq!(offset.align_to(padding_align) + padding, target_offset);
    result.push(cx.type_padding_filler(padding, padding_align));

    result.push(field.gcc_type(cx));
    offset = target_offset + field.size;
    prev_effective_align = effective_field_align;
}

if !constraints.is_empty() {
    // FIXME(higher_ranked_auto): Should we register assumptions here?
    // We otherwise would get spurious errors if normalizing an implied
    // outlives bound required proving some higher-ranked coroutine obl.
    let QueryRegionConstraints { constraints, assumptions: _ } = constraints;
    let cause = ObligationCause::misc(span, body_id);
    for &QueryRegionConstraint { constraint, visible_for_leak_check: vis, .. } in &constraints {
        match constraint {
            ty::RegionConstraint::Outlives(predicate) => {
                infcx.register_outlives_constraint(predicate, vis, &cause)
            }
            ty::RegionConstraint::Eq(predicate) => {
                infcx.register_region_eq_constraint(predicate, vis, &cause)
            }
        }
    }
}

if generics.own_requires_monomorphization()
        // When an EII implementation is automatically generated by the `#[eii]` macro,
        // it will directly refer to the foreign item, not through a macro.
        // We don't want to emit this error if it's an implementation that's generated by the `#[eii]` macro,
        // since in that case it looks like a duplicate error: the declaration of the EII already can't contain generics.
        // So, we check here if at least one of the eii impls has ImplResolution::Macro, which indicates it's
        // not generated as part of the declaration.
        && find_attr!(tcx, external_impl, EiiImpls(impls) if impls.iter().any(|i| matches!(i.resolution, EiiImplResolution::Macro(_)))
        )
    {
        tcx.dcx().emit_err(EiiWithGenerics {
            span: tcx.def_span(external_impl),
            attr: eii_attr_span,
            eii_name,
            impl_name: tcx.item_name(external_impl),
        });
    }

if impls_default_trait && ends_of_record_list {
    // FIXME: This should make use of scope_def like completions so we get all the other goodies
    // that is we should handle this like actually completing the default function
    let completion_text = "..Default::default()";
    let mut item = CompletionItem::new(
        SymbolKind::Field,
        ctx.source_range(),
        SmolStr::new_static(completion_text),
        ctx.edition,
    );
    let completion_text =
        completion_text.strip_prefix(ctx.token.text()).unwrap_or(completion_text);
    item.insert_text(completion_text).set_relevance(CompletionRelevance {
        postfix_match: Some(CompletionRelevancePostfixMatch::Exact),
        ..Default::default()
    });
    item.add_to(acc, ctx.db);
}

if matches!(tcx.def_kind(defining_ty_def_id), DefKind::AssocFn | DefKind::AssocConst { .. })
        {
            for &(ty, _) in tcx.assumed_wf_types(tcx.local_parent(defining_ty_def_id)) {
                let result: Result<_, ErrorGuaranteed> = param_env
                    .and(DeeplyNormalize { value: ty })
                    .fully_perform(self.infcx, self.infcx.root_def_id, span);
                let Ok(TypeOpOutput { output: norm_ty, constraints: c, .. }) = result else {
                    continue;
                };

                constraints.extend(c);

                // We currently add implied bounds from the normalized ty only.
                // This is more conservative and matches wfcheck behavior.
                let c = self.add_implied_bounds(norm_ty, span);
                constraints.extend(c);
            }
        }

while let Some((mplace, path)) = ref_tracking.next() {
    let mode = match ecx.tcx.static_mutability(cid.instance.def_id()) {
        _ if cid.promoted.is_some() => CtfeValidationMode::Promoted,
        Some(mutbl) => CtfeValidationMode::Static { mutbl }, // a `static`
        None => {
            // This is a normal `const` (not promoted).
            // The outermost allocation is always only copied, so having `UnsafeCell` in there
            // is okay despite them being in immutable memory.
            CtfeValidationMode::Const { allow_immutable_unsafe_cell: !inner }
        }
    };
    ecx.const_validate_operand(&mplace.into(), path, &mut ref_tracking, mode)
        .report_err()
        // Instead of just reporting the `InterpError` via the usual machinery, we give a more targeted
        // error about the validation failure.
        .map_err(|error| report_validation_error(&ecx, cid, error, alloc_id))?;
    inner = true;
}

if let Some(Value::Table(assign)) = config.get("assign") {
    if let Some(Value::Table(owners)) = assign.get("owners") {
        for path_str in owners.keys() {
            // Remove quotes and leading slash from the path
            let clean_path = path_str.trim_matches('"').trim_start_matches('/');
            let full_path = path.join(clean_path);

            if !full_path.exists() {
                check.error(format!(
                    "triagebot.toml [assign.owners] contains path '{clean_path}' which doesn't exist"
                ));
            }
        }
    } else {
        check.error(
            "triagebot.toml missing [assign.owners] section, this wrong for rust-lang/rust repo."
        );
    }
}

for (lint_name, &lint_span) in &self.declared_lints {
    // When using the `declare_tool_lint!` macro, the original `lint_span`'s
    // file points to "<rustc macros>".
    // `compiletest-rs` thinks that's an error in a different file and
    // just ignores it. This causes the test in compile-fail/lint_pass
    // not able to capture the error.
    // Therefore, we need to climb the macro expansion tree and find the
    // actual span that invoked `declare_tool_lint!`:
    let lint_span = lint_span.ctxt().outer_expn_data().call_site;

    if !self.registered_lints.contains(lint_name) {
        span_lint(
            cx,
            LINT_WITHOUT_LINT_PASS,
            lint_span,
            format!("the lint `{lint_name}` is not added to any `LintPass`"),
        );
    }
}

if let Some(existing) =
            self.def_path_hash_to_index.insert(&local_hash, &def_id.local_def_index)
        {
            let def_path1 = self.def_path(LocalDefId { local_def_index: existing });
            let def_path2 = self.def_path(def_id);

            // Continuing with colliding DefPathHashes can lead to correctness
            // issues. We must abort compilation.
            //
            // The likelihood of such a collision is very small, so actually
            // running into one could be indicative of a poor hash function
            // being used.
            //
            // See the documentation for DefPathHash for more information.
            panic!(
                "found DefPathHash collision between {def_path1:#?} and {def_path2:#?}. \
                    Compilation cannot continue."
            );
        }

if parser_replacements_start == parser_replacements_end
            && inner_attr_parser_replacements.is_empty()
        {
            ThinVec::new()
        } else {
            // Grab any replace ranges that occur *inside* the current AST node. Convert them
            // from `ParserRange` form to `NodeRange` form. We will perform the actual
            // replacement only when we convert the `LazyAttrTokenStream` to an
            // `AttrTokenStream`.
            self.capture_state.parser_replacements
                [parser_replacements_start..parser_replacements_end]
                .iter()
                .cloned()
                .chain(inner_attr_parser_replacements)
                .map(|(parser_range, data)| {
                    (NodeRange::new(parser_range, collect_pos.start_pos), data)
                })
                .collect()
        }

if let Some(ty) = self.state.cur_ty.builtin_deref(self.include_raw_pointers) {
    debug_assert_eq!(ty, self.infcx().resolve_vars_if_possible(ty));
    // NOTE: we may still need to normalize the built-in deref in case
    // we have some type like `&<Ty as Trait>::Assoc`, since users of
    // autoderef expect this type to have been structurally normalized.
    if let TyKind::Alias(..) = ty.kind() {
        let (normalized_ty, obligations) =
            structurally_normalize_ty(self.infcx(), self.param_env(), ty, self.span)?;
        self.state.obligations.extend(obligations);
        (AutoderefKind::Builtin, normalized_ty)
    } else {
        (AutoderefKind::Builtin, ty)
    }
} else if let Some(ty) = self.overloaded_deref_ty(self.state.cur_ty) {
    // The overloaded deref check already normalizes the pointee type.
    (AutoderefKind::Overloaded, ty)
} else {
    return None;
}

match parent_expr.kind {
    ExprKind::MethodCall(segment, recv, ..)
        // We currently only lint `str` methods (which `String` can deref to), so a `.is_str()` check is sufficient here
        // (contrary to the `ExprKind::Index` case which needs to handle both with `is_string_like` because `String` implements
        // `Index` directly and no deref to `str` would happen in that case).
        if cx.typeck_results().expr_ty_adjusted(recv).peel_refs().is_str()
            && BYTE_INDEX_METHODS.contains(&segment.ident.name)
            && eq_expr_value(cx, expr.span.ctxt(), chars_recv, recv) =>
    {
        "passing a character position to a method that expects a byte index"
    },
    ExprKind::Index(target, ..)
        if is_string_like(cx.typeck_results().expr_ty_adjusted(target).peel_refs())
            && eq_expr_value(cx, expr.span.ctxt(), chars_recv, target) =>
    {
        "indexing into a string with a character position where a byte index is expected"
    },
    _ => return,
}

match self.kind {
    StopKind::Attr => {
        if cx.sess().source_map().is_multiline(self.span) {
            suggestions.extend([
                (self.span.shrink_to_lo(), "/* ".into()),
                (self.span.shrink_to_hi(), " */".into()),
            ]);
        } else {
            suggestions.push((self.span.shrink_to_lo(), "// ".into()));
        }
    },
    StopKind::Doc(CommentKind::Line) => suggestions.push((self.span.shrink_to_lo(), "// ".into())),
    StopKind::Doc(CommentKind::Block) => {
        // /** outer */  /*! inner */
        //  ^             ^
        let asterisk = self.span.from_inner(InnerSpan::new(1, 2));
        suggestions.push((asterisk, String::new()));
    },
}

for component in components {
    let pkg = manifest
        .pkg
        .get(*component)
        .ok_or_else(|| anyhow::anyhow!("missing component from manifest: {}", component))?;
    for target in pkg.target.values() {
        for pair in &[(&target.url, &target.hash), (&target.xz_url, &target.xz_hash)] {
            if let (Some(url), Some(sha256)) = pair {
                let url = url
                    .strip_prefix(&prefix)
                    .ok_or_else(|| {
                        anyhow::anyhow!("url doesn't start with dist server base: {}", url)
                    })?
                    .to_string();
                self.checksums.insert(url, sha256.clone());
            }
        }
    }
}

if let ty::Ref(_, ref_type, _) = collect_output_adjusted_type.kind()
        // the turbofish for collect is ::<Vec<String>>
        && let ty::Slice(slice) = *ref_type.kind()
        && slice.is_lang_item(cx, LangItem::String)
        // the argument for join is ""
        && let ExprKind::Lit(spanned) = &join_arg.kind
        && let LitKind::Str(symbol, _) = spanned.node
        && symbol.is_empty()
    {
        span_lint_and_sugg(
            cx,
            UNNECESSARY_JOIN,
            span.with_hi(expr.span.hi()),
            r#"called `.collect::<Vec<String>>().join("")` on an iterator"#,
            "consider using",
            "collect::<String>()".to_owned(),
            applicability,
        );
    }

if (env::var_os("RUSTC_PRINT_STEP_TIMINGS").is_some()
        || env::var_os("RUSTC_PRINT_STEP_RUSAGE").is_some())
        && let Some(crate_name) = crate_name
    {
        let dur = start.elapsed();
        // If the user requested resource usage data, then
        // include that in addition to the timing output.
        let rusage_data =
            env::var_os("RUSTC_PRINT_STEP_RUSAGE").and_then(|_| format_rusage_data(child));
        eprintln!(
            "[RUSTC-TIMING] {} test:{} {}.{:03}{}{}",
            crate_name,
            is_test,
            dur.as_secs(),
            dur.subsec_millis(),
            if rusage_data.is_some() { " " } else { "" },
            rusage_data.unwrap_or_default(),
        );
    }

for (block, data) in body.basic_blocks.iter_enumerated() {
    for (statement_index, stmt) in data.statements.iter().enumerate() {
        if let StatementKind::BackwardIncompatibleDropHint { place, reason: _ } = &stmt.kind {
            let ty = place.ty(body, tcx).ty;
            if ty_dropped_components
                .entry(ty)
                .or_insert_with(|| extract_component_with_significant_dtor(tcx, typing_env, ty))
                .is_empty()
            {
                continue;
            }
            bid_per_block
                .entry(block)
                .or_insert(vec![])
                .push((Location { block, statement_index }, &**place));
            bid_places.insert(&**place);
        }
    }
}

for (_name, dynstr, _ver, symbol_type, size) in syms.iter().copied() {
    let sym_type = match symbol_type {
        DllImportSymbolType::Function => elf::STT_FUNC,
        DllImportSymbolType::Static => elf::STT_OBJECT,
        DllImportSymbolType::ThreadLocal => elf::STT_TLS,
    };
    let section =
        if symbol_type == DllImportSymbolType::Static { data_section } else { text_section };
    stub.write_dynamic_symbol(&write::Sym {
        name: Some(dynstr),
        st_info: (elf::STB_GLOBAL << 4) | sym_type,
        st_other: elf::STV_DEFAULT,
        section: Some(section),
        st_shndx: 0, // ignored by object in favor of the `section` field
        st_value,
        st_size: size.bytes(),
    });
    st_value += 8;
}

if !ret_expr.span.from_expansion()
                // Check if a function call.
                && let ExprKind::Call(func, [arg]) = ret_expr.kind
                && func.res(cx).ctor_parent(cx).is_lang_item(cx, lang_item)
                // Make sure the function argument does not contain a return expression.
                && !contains_return(arg)
            {
                suggs.push((
                    ret_expr.span,
                    if inner_type.is_unit() {
                        String::new()
                    } else {
                        snippet(cx, arg.span.source_callsite(), "..").to_string()
                    },
                ));
                true
            } else {
                false
            }

if !dox.is_empty() {
    let may_have_link = dox.contains(&[':', '['][..]);
    let may_have_block_comment_or_html = dox.contains(['<', '>']);
    // ~~~rust
    // // This is a real, supported commonmark syntax for block code
    // ~~~
    let may_have_code = dox.contains(&['~', '`', '\t'][..]) || dox.contains("    ");
    if may_have_link {
        bare_urls::visit_item(self.cx, item, hir_id, &dox);
        redundant_explicit_links::visit_item(self.cx, item, hir_id);
    }
    if may_have_code {
        check_code_block_syntax::visit_item(self.cx, item, &dox);
        unescaped_backticks::visit_item(self.cx, item, hir_id, &dox);
    }
    if may_have_block_comment_or_html {
        html_tags::visit_item(self.cx, item, hir_id, &dox);
    }
}
